@startuml
actor User #red;line:red;text:green;back:white;;

participant QuerySet  {line:black;color:#084298;}#yellow;line:red;text:green;back:lightYellow;; 
participant "QueryParser" as QP{line:black;color:#084298;}#white;line:red;text:green;back:lightYellow;;  
participant Tokenizer{T}   {line:black;color:#084298;}#white;line:red;text:green;back:lightYellow;; 

User ->> QS :1 QuerySet()   
activate QS    
QS <- - T   


note right of QS::add("longitude", "* /CLON")\n\n== add == \n- field = longitude\n- pattern= * / CLON 


QP->T: tokenize(queryString)     
return tokens  

loop [all subqueries]      
     create participant qQ <<query>>       
      note over QQ:"*"/CLO N"\ nfield="longitud e""        
end loop    

@enduml
